[HttpDelete("{id:int}")]
    public async Task<IActionResult> Delete(int id, CancellationToken cancellationToken)
    {
        var entity = await db.Categories.FirstOrDefaultAsync(c => c.Id == id, cancellationToken);
        if (entity is null)
            return NotFound();

        var hasExpenses = await db.Expenses.AnyAsync(e => e.CategoryId == id, cancellationToken);
        if (hasExpenses)
            return Conflict(new { message = "No se puede eliminar la categoría porque tiene gastos asociados." });

        db.Categories.Remove(entity);
        await db.SaveChangesAsync(cancellationToken);
        return NoContent();
    }

