[HttpGet]
    public async Task<ActionResult<IEnumerable<CategoryResponse>>> GetAll(CancellationToken cancellationToken)
    {
        var list = await db.Categories
            .AsNoTracking()
            .OrderBy(c => c.Name)
            .Select(c => new CategoryResponse(c.Id, c.Name))
            .ToListAsync(cancellationToken);
        return Ok(list);
    }

[HttpGet("{id:int}")]
    public async Task<ActionResult<CategoryResponse>> GetById(int id, CancellationToken cancellationToken)
    {
        var row = await db.Categories.AsNoTracking().FirstOrDefaultAsync(c => c.Id == id, cancellationToken);
        if (row is null)
            return NotFound();
        return Ok(new CategoryResponse(row.Id, row.Name));
    }

[HttpGet]
    public async Task<ActionResult<IEnumerable<ExpenseResponse>>> GetAll(
        [FromQuery] DateOnly? from,
        [FromQuery] DateOnly? to,
        [FromQuery] int? categoryId,
        CancellationToken cancellationToken)
    {
        var query = db.Expenses.AsNoTracking().Include(e => e.Category).AsQueryable();

        if (from is not null)
            query = query.Where(e => e.Date >= from);
        if (to is not null)
            query = query.Where(e => e.Date <= to);
        if (categoryId is not null)
            query = query.Where(e => e.CategoryId == categoryId);

        var list = await query
            .OrderByDescending(e => e.Date)
            .ThenByDescending(e => e.Id)
            .Select(e => new ExpenseResponse(
                e.Id,
                e.Amount,
                e.Date,
                e.Description,
                e.CategoryId,
                e.Category != null ? e.Category.Name : null))
            .ToListAsync(cancellationToken);

        return Ok(list);
    }

[HttpGet("{id:int}")]
    public async Task<ActionResult<ExpenseResponse>> GetById(int id, CancellationToken cancellationToken)
    {
        var row = await db.Expenses
            .AsNoTracking()
            .Include(e => e.Category)
            .FirstOrDefaultAsync(e => e.Id == id, cancellationToken);
        if (row is null)
            return NotFound();
        return Ok(new ExpenseResponse(
            row.Id,
            row.Amount,
            row.Date,
            row.Description,
            row.CategoryId,
            row.Category?.Name));
    }

[HttpPost]
    public async Task<ActionResult<CategoryResponse>> Create(
        [FromBody] CategoryCreateRequest request,
        CancellationToken cancellationToken)
    {
        var name = request.Name.Trim();
        if (string.IsNullOrEmpty(name))
            return BadRequest();

        var exists = await db.Categories.AnyAsync(c => c.Name == name, cancellationToken);
        if (exists)
            return Conflict(new { message = "Ya existe una categoría con ese nombre." });

        var entity = new Category { Name = name };
        db.Categories.Add(entity);
        await db.SaveChangesAsync(cancellationToken);
        return CreatedAtAction(nameof(GetById), new { id = entity.Id }, new CategoryResponse(entity.Id, entity.Name));
    }

[HttpPost]
    public async Task<ActionResult<ExpenseResponse>> Create(
        [FromBody] ExpenseCreateRequest request,
        CancellationToken cancellationToken)
    {
        if (!ModelState.IsValid)
            return ValidationProblem(ModelState);

        if (request.Amount <= 0)
            return BadRequest(new { message = "El importe debe ser mayor que cero." });

        var categoryId = request.CategoryId!.Value;
        var categoryExists = await db.Categories.AnyAsync(c => c.Id == categoryId, cancellationToken);
        if (!categoryExists)
            return BadRequest(new { message = "La categoría no existe." });

        var entity = new Expense
        {
            Amount = request.Amount,
            Date = request.Date,
            Description = request.Description.Trim(),
            CategoryId = categoryId
        };
        db.Expenses.Add(entity);
        await db.SaveChangesAsync(cancellationToken);

        await db.Entry(entity).Reference(e => e.Category).LoadAsync(cancellationToken);
        return CreatedAtAction(
            nameof(GetById),
            new { id = entity.Id },
            new ExpenseResponse(
                entity.Id,
                entity.Amount,
                entity.Date,
                entity.Description,
                entity.CategoryId,
                entity.Category?.Name));
    }

[HttpPut("{id:int}")]
    public async Task<IActionResult> Update(int id, [FromBody] CategoryUpdateRequest request, CancellationToken cancellationToken)
    {
        var name = request.Name.Trim();
        if (string.IsNullOrEmpty(name))
            return BadRequest();

        var entity = await db.Categories.FirstOrDefaultAsync(c => c.Id == id, cancellationToken);
        if (entity is null)
            return NotFound();

        var duplicate = await db.Categories.AnyAsync(c => c.Id != id && c.Name == name, cancellationToken);
        if (duplicate)
            return Conflict(new { message = "Ya existe otra categoría con ese nombre." });

        entity.Name = name;
        await db.SaveChangesAsync(cancellationToken);
        return NoContent();
    }

[HttpPut("{id:int}")]
    public async Task<IActionResult> Update(int id, [FromBody] ExpenseUpdateRequest request, CancellationToken cancellationToken)
    {
        if (!ModelState.IsValid)
            return ValidationProblem(ModelState);

        if (request.Amount <= 0)
            return BadRequest(new { message = "El importe debe ser mayor que cero." });

        var categoryId = request.CategoryId!.Value;
        var categoryExists = await db.Categories.AnyAsync(c => c.Id == categoryId, cancellationToken);
        if (!categoryExists)
            return BadRequest(new { message = "La categoría no existe." });

        var entity = await db.Expenses.FirstOrDefaultAsync(e => e.Id == id, cancellationToken);
        if (entity is null)
            return NotFound();

        entity.Amount = request.Amount;
        entity.Date = request.Date;
        entity.Description = request.Description.Trim();
        entity.CategoryId = categoryId;
        await db.SaveChangesAsync(cancellationToken);
        return NoContent();
    }
